import React from "react";
import { ArrowLeft, Download } from "lucide-react";
import { formatCurrency } from "../helpers/helpers";
import { jsPDF } from "jspdf";

export default function TransactionReceiptScreen({ transaction, onBack, darkMode }) {
  if (!transaction) return null;

  const isDeposit = transaction.type.includes("deposit");

  const handleDownloadPDF = () => {
    const doc = new jsPDF();
    doc.setFontSize(18);
    doc.text("Transaction Receipt", 14, 22);
    doc.setFontSize(12);
    doc.text(`Type: ${transaction.title}`, 14, 40);
    doc.text(
      `Amount: ${isDeposit ? "+" : "-"}₦${formatCurrency(transaction.amount)}`,
      14,
      50
    );
    doc.text(`Date: ${transaction.date}`, 14, 60);
    doc.text(`Reference: ${transaction.reference || "N/A"}`, 14, 70);
    doc.text("Status: Transaction Successful", 14, 80);
    doc.save("transaction_receipt.pdf");
  };

  return (
    <div
      className={`min-h-screen px-5 pt-6 pb-24 ${
        darkMode ? "bg-gray-900" : "bg-[#f4f6fb]"
      }`}
    >
      {/* Header */}
      <div className="flex items-center gap-3 mb-8">
        <button onClick={onBack}>
          <ArrowLeft
            className={`w-6 h-6 ${darkMode ? "text-gray-300" : "text-gray-700"}`}
          />
        </button>
        <h1
          className={`text-xl font-semibold ${
            darkMode ? "text-white" : "text-gray-900"
          }`}
        >
          Transaction Receipt
        </h1>
      </div>

      {/* Receipt Card */}
      <div
        className={`rounded-2xl p-6 shadow-sm space-y-4 ${
          darkMode ? "bg-gray-800 shadow-gray-700" : "bg-white shadow-sm"
        }`}
      >
        <div className="flex justify-between">
          <span className={`${darkMode ? "text-gray-400" : "text-gray-500"}`}>Type</span>
          <span className={`font-semibold ${darkMode ? "text-white" : "text-gray-900"}`}>
            {transaction.title}
          </span>
        </div>

        <div className="flex justify-between">
          <span className={`${darkMode ? "text-gray-400" : "text-gray-500"}`}>Amount</span>
          <span
            className={`font-bold ${
              isDeposit
                ? "text-emerald-500"
                : darkMode
                ? "text-gray-200"
                : "text-gray-900"
            }`}
          >
            {isDeposit ? "+" : "-"}₦{formatCurrency(transaction.amount)}
          </span>
        </div>

        <div className="flex justify-between">
          <span className={`${darkMode ? "text-gray-400" : "text-gray-500"}`}>Date</span>
          <span className={`font-medium ${darkMode ? "text-white" : "text-gray-900"}`}>
            {transaction.date}
          </span>
        </div>

        {transaction.reference && (
          <div className="flex justify-between">
            <span className={`${darkMode ? "text-gray-400" : "text-gray-500"}`}>Reference</span>
            <span className={`font-medium ${darkMode ? "text-white" : "text-gray-900"}`}>
              {transaction.reference}
            </span>
          </div>
        )}

        <div className="pt-4 border-t border-gray-200 dark:border-gray-700 flex flex-col items-center gap-3">
          <p className="text-center text-sm text-emerald-500 font-medium">
            Transaction Successful
          </p>
          <button
            onClick={handleDownloadPDF}
            className="flex items-center gap-2 px-4 py-2 bg-emerald-600 text-white rounded-xl font-semibold hover:bg-emerald-700 transition"
          >
            <Download size={16} /> Download PDF
          </button>
        </div>
      </div>
    </div>
  );
}
